mapper.select:
SELECT COALESCE(MAX(floor_no), 0) + 1
FROM comments
WHERE post_id = #{postId}

mapper.update:
UPDATE comments
SET like_count = GREATEST(0, like_count + #{delta})
WHERE comment_id = #{commentId}

mapper.select:
SELECT COUNT(*)
FROM comment_likes
WHERE comment_id = #{commentId}
  AND user_id = #{userId}

mapper.delete:
DELETE FROM comment_likes
WHERE comment_id = #{commentId}
  AND user_id = #{userId}
